'use client';

import { useState } from 'react';
import { Search, Filter, MoreHorizontal, GraduationCap, Eye, Edit, Mail, Award, Calendar } from 'lucide-react';
import Link from 'next/link';
import { UserProfile } from '@/src/lib/types/users_turmas';

interface AlunosListProps {
    alunos: UserProfile[];
}

export function AlunosList({ alunos }: AlunosListProps) {
    const [searchTerm, setSearchTerm] = useState('');
    const [filterNivel, setFilterNivel] = useState('todos');

    const filteredAlunos = alunos.filter(aluno => {
        const matchesSearch = (aluno.full_name?.toLowerCase() || '').includes(searchTerm.toLowerCase()) ||
            (aluno.email?.toLowerCase() || '').includes(searchTerm.toLowerCase());

        // Simulação de filtro de nível (assumindo que nivel_atual existe ou vamos mockar se for null)
        const nivel = (aluno as any).nivel_atual || 'iniciante';
        const matchesFilter = filterNivel === 'todos' || nivel.toLowerCase() === filterNivel.toLowerCase();

        return matchesSearch && matchesFilter;
    });

    return (
        <div className="space-y-6">
            {/* Toolbar */}
            <div className="flex flex-col sm:flex-row gap-4 justify-between bg-white p-4 rounded-xl shadow-sm border border-gray-100">
                <div className="relative flex-1">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-5 h-5" />
                    <input
                        type="text"
                        placeholder="Buscar aluno por nome ou email..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        className="w-full pl-10 pr-4 py-2.5 rounded-lg border border-gray-200 focus:ring-2 focus:ring-red-500 focus:border-red-500 outline-none transition-all"
                    />
                </div>
                <div className="flex gap-2">
                    <select
                        value={filterNivel}
                        onChange={(e) => setFilterNivel(e.target.value)}
                        className="px-4 py-2.5 rounded-lg border border-gray-200 bg-gray-50 text-gray-700 outline-none focus:ring-2 focus:ring-red-500 cursor-pointer"
                    >
                        <option value="todos">Todos os Níveis</option>
                        <option value="iniciante">Iniciante</option>
                        <option value="intermediário">Intermediário</option>
                        <option value="avançado">Avançado</option>
                    </select>
                </div>
            </div>

            {/* Content */}
            <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left text-sm text-gray-600">
                        <thead className="bg-gray-50 text-gray-900 font-semibold border-b border-gray-200">
                            <tr>
                                <th className="px-6 py-4">Aluno</th>
                                <th className="px-6 py-4">Contato</th>
                                <th className="px-6 py-4">Status Acadêmico</th>
                                <th className="px-6 py-4">Matrícula</th>
                                <th className="px-6 py-4 text-right">Ações</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                            {filteredAlunos.length > 0 ? (
                                filteredAlunos.map((aluno: any) => (
                                    <tr key={aluno.id} className="hover:bg-gray-50 transition-colors group">
                                        <td className="px-6 py-4">
                                            <div className="flex items-center gap-3">
                                                <div className="w-10 h-10 rounded-full bg-gradient-to-br from-red-100 to-orange-100 flex items-center justify-center text-red-700 font-bold shadow-sm">
                                                    {aluno.avatar_url ? (
                                                        <img src={aluno.avatar_url} alt="" className="w-full h-full object-cover rounded-full" />
                                                    ) : (
                                                        aluno.full_name?.charAt(0) || 'A'
                                                    )}
                                                </div>
                                                <div>
                                                    <div className="font-semibold text-gray-900">{aluno.full_name}</div>
                                                    <div className="text-xs text-gray-500 flex items-center gap-1">
                                                        <Calendar className="w-3 h-3" />
                                                        Desde {new Date(aluno.created_at || Date.now()).toLocaleDateString('pt-BR')}
                                                    </div>
                                                </div>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="flex items-center gap-2 text-gray-600">
                                                <Mail className="w-4 h-4 text-gray-400" />
                                                {aluno.email}
                                            </div>
                                        </td>
                                        <td className="px-6 py-4">
                                            <div className="flex flex-col gap-1">
                                                <span className={`inline-flex items-center w-fit px-2.5 py-0.5 rounded-full text-xs font-medium ${(aluno.nivel_atual || 'iniciante') === 'avançado' ? 'bg-purple-100 text-purple-700' :
                                                        (aluno.nivel_atual || 'iniciante') === 'intermediário' ? 'bg-blue-100 text-blue-700' :
                                                            'bg-green-100 text-green-700'
                                                    }`}>
                                                    <Award className="w-3 h-3 mr-1" />
                                                    {(aluno.nivel_atual || 'Iniciante').charAt(0).toUpperCase() + (aluno.nivel_atual || 'iniciante').slice(1)}
                                                </span>
                                            </div>
                                        </td>
                                        <td className="px-6 py-4 font-mono text-sm text-gray-500">
                                            #{aluno.matricula || '---'}
                                        </td>
                                        <td className="px-6 py-4 text-right">
                                            <div className="flex items-center justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                                <Link
                                                    href={`/admin/alunos/${aluno.id}`}
                                                    className="p-2 text-gray-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors border border-transparent hover:border-indigo-100"
                                                    title="Ver Perfil"
                                                >
                                                    <Eye className="w-4 h-4" />
                                                </Link>
                                                {/* <Link 
                                                    href={`/admin/alunos/editar/${aluno.id}`}
                                                    className="p-2 text-gray-500 hover:text-orange-600 hover:bg-orange-50 rounded-lg transition-colors border border-transparent hover:border-orange-100"
                                                    title="Editar"
                                                >
                                                    <Edit className="w-4 h-4" />
                                                </Link> */}
                                            </div>
                                        </td>
                                    </tr>
                                ))
                            ) : (
                                <tr>
                                    <td colSpan={5} className="px-6 py-12 text-center text-gray-500 bg-white">
                                        <div className="flex flex-col items-center justify-center gap-3">
                                            <div className="w-12 h-12 bg-gray-100 rounded-full flex items-center justify-center">
                                                <Search className="w-6 h-6 text-gray-400" />
                                            </div>
                                            <p className="font-medium">Nenhum aluno encontrado</p>
                                            <p className="text-sm">Tente buscar por outro termo ou limpe os filtros.</p>
                                        </div>
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
                <div className="px-6 py-4 border-t border-gray-200 bg-gray-50 text-xs text-gray-500 flex justify-between items-center">
                    <span>Mostrando {filteredAlunos.length} de {alunos.length} alunos</span>
                    {/* Paginação poderia vir aqui */}
                </div>
            </div>
        </div>
    );
}
